const body = $input.first().json.body || $input.first().json;

// Loop prevention: skip if the change came from svc-n8n-sync or n8n Sync
const updatedBy = body._embedded?.user?.name || body._embedded?.updatedBy?.name || '';
if (updatedBy === 'svc-n8n-sync' || updatedBy === 'n8n Sync') {
  return [];
}

const action = body.action || '';
const wp = body._embedded?.work_package || body.work_package || body;
const wpId = wp.id || body.id;
const subject = wp.subject || body.subject || '';
const status = wp._embedded?.status?.name || body.status || '';
const description = wp.description?.raw || wp.description || '';
const projectId = wp._embedded?.project?.id || body.project_id;
const typeTitle = wp._embedded?.type?.name || body.type || '';
const parentId = wp._embedded?.parent?.id || body.parent_id || null;

return [{
  json: {
    action,
    wpId,
    subject,
    status,
    description,
    projectId,
    typeTitle,
    parentId,
    updatedBy,
    rawBody: body
  }
}];

// Placeholder: actual sync table lookup wired in n8n UI via DB node
// This code node passes through for now; replace with Postgres node in production
const item = $input.first().json;

// Expected: query app.op_sync_map WHERE op_wp_id = item.wpId
// Returns: { ghIssueNumber, ghRepo, gsdTaskId, lastSyncedAt }
const syncRecord = {
  ghIssueNumber: null,
  ghRepo: 'sudoshi/Parthenon',
  gsdTaskId: null,
  lastSyncedAt: null,
  found: false
};

return [{ json: { ...item, syncRecord } }];

const item = $input.first().json;
const { wpId, subject, status, description, syncRecord } = item;

// Map OP status to GitHub state
const statusMap = {
  'New': 'open',
  'In Progress': 'open',
  'In Review': 'open',
  'Closed': 'closed',
  'Rejected': 'closed',
  'Done': 'closed',
  'On hold': 'open'
};
const ghState = statusMap[status] || 'open';

// Determine GitHub labels from OP status
const labelMap = {
  'In Progress': ['in-progress'],
  'In Review': ['in-review'],
  'On hold': ['on-hold'],
  'Done': ['done']
};
const labels = (labelMap[status] || []).concat(['synced-by:n8n']);

const action = syncRecord.found ? 'update' : 'create';

return [{
  json: {
    ...item,
    github: {
      action,
      repo: syncRecord.ghRepo || 'sudoshi/Parthenon',
      issueNumber: syncRecord.ghIssueNumber,
      title: subject,
      body: description ? `${description}\n\n---\n*Synced from OpenProject WP #${wpId}*` : `*Synced from OpenProject WP #${wpId}*`,
      state: ghState,
      labels
    }
  }
}];
